import sys

def main():
    n = int(sys.stdin.readline())
    s = sys.stdin.readline().strip()

    t_count = 0
    a_count = 0

    for char in s:
        if char == 'T':
            t_count += 1
        else:
            a_count += 1

    if t_count > a_count:
        print('T')
    elif a_count > t_count:
        print('A')
    else:
        # They have the same number of wins, find who reached it first
        count = 0
        for char in s:
            if char == 'T':
                count += 1
            else:
                count -= 1
            if count == 0:
                print('T')
                return
        print('A')

if __name__ == "__main__":
    main()
